import type { SecurityParameterGroup } from '@mintlify/validation';
import { describe, expect, it } from 'vitest';

import { convertSecurityParameterSection } from '../src/mcp-server/src/tools/helpers.js';
import type { SimpleRecord } from '../src/mcp-server/src/utils.js';

describe('convertSecurityParameterSection', () => {
  describe('API Key type', () => {
    it('should handle API key with environment variable present', () => {
      const securityParameters: SecurityParameterGroup = {
        'x-api-key': {
          type: 'apiKey',
          description: 'API Key for authentication',
        },
      };

      const envVariables: SimpleRecord = {
        header: {
          'x-api-key': {
            API_KEY: 'my-secret-key',
          },
        },
      };

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'header');

      expect(result).toEqual([
        {
          key: 'x-api-key',
          value: 'my-secret-key',
        },
      ]);
    });

    it('should handle API key without environment variable', () => {
      const securityParameters: SecurityParameterGroup = {
        'api-token': {
          type: 'apiKey',
        },
      };

      const envVariables: SimpleRecord = {};

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'query');

      expect(result).toEqual([
        {
          key: 'api-token',
          value: undefined,
        },
      ]);
    });
  });

  describe('HTTP type', () => {
    it('should handle HTTP bearer scheme with environment variable', () => {
      const securityParameters: SecurityParameterGroup = {
        Authorization: {
          type: 'http',
          scheme: 'bearer',
          description: 'Bearer token authentication',
        },
      };

      const envVariables: SimpleRecord = {
        header: {
          Authorization: {
            HTTP: {
              bearer: 'Bearer token123',
            },
          },
        },
      };

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'header');

      expect(result).toEqual([
        {
          key: 'Authorization',
          value: 'Bearer token123',
        },
      ]);
    });

    it('should handle HTTP basic scheme with environment variable', () => {
      const securityParameters: SecurityParameterGroup = {
        Authorization: {
          type: 'http',
          scheme: 'basic',
        },
      };

      const envVariables: SimpleRecord = {
        header: {
          Authorization: {
            HTTP: {
              basic: 'Basic dXNlcjpwYXNz',
            },
          },
        },
      };

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'header');

      expect(result).toEqual([
        {
          key: 'Authorization',
          value: 'Basic dXNlcjpwYXNz',
        },
      ]);
    });

    it('should handle HTTP scheme without environment variable', () => {
      const securityParameters: SecurityParameterGroup = {
        Authorization: {
          type: 'http',
          scheme: 'bearer',
        },
      };

      const envVariables: SimpleRecord = {};

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'header');

      expect(result).toEqual([
        {
          key: 'Authorization',
          value: undefined,
        },
      ]);
    });
  });

  describe('OAuth2 type', () => {
    it('should handle OAuth2 parameters', () => {
      const securityParameters: SecurityParameterGroup = {
        oauth2Auth: {
          type: 'oauth2',
          description: 'OAuth2 authentication',
        },
      };

      const envVariables: SimpleRecord = {};

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'header');

      expect(result).toEqual([
        {
          key: 'oauth2Auth',
          value: undefined,
        },
      ]);
    });
  });

  describe('Multiple security parameters', () => {
    it('should handle multiple security parameters in one call', () => {
      const securityParameters: SecurityParameterGroup = {
        'x-api-key': {
          type: 'apiKey',
        },
        'x-client-id': {
          type: 'apiKey',
        },
        Authorization: {
          type: 'http',
          scheme: 'bearer',
        },
      };

      const envVariables: SimpleRecord = {
        query: {
          'x-api-key': {
            API_KEY: 'key1',
          },
        },
      };

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'query');

      expect(result).toHaveLength(3); // Each parameter generates 1 entry
      expect(result).toContainEqual({
        key: 'x-api-key',
        value: 'key1',
      });
      expect(result).toContainEqual({
        key: 'x-client-id',
        value: undefined,
      });
      expect(result).toContainEqual({
        key: 'Authorization',
        value: undefined,
      });
    });
  });

  describe('Different locations', () => {
    it('should handle query location', () => {
      const securityParameters: SecurityParameterGroup = {
        apiKey: {
          type: 'apiKey',
        },
      };

      const envVariables: SimpleRecord = {
        query: {
          apiKey: {
            API_KEY: 'query-key',
          },
        },
      };

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'query');

      expect(result).toContainEqual({
        key: 'apiKey',
        value: 'query-key',
      });
    });

    it('should handle cookie location', () => {
      const securityParameters: SecurityParameterGroup = {
        sessionToken: {
          type: 'apiKey',
        },
      };

      const envVariables: SimpleRecord = {
        cookie: {
          sessionToken: {
            API_KEY: 'session-123',
          },
        },
      };

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'cookie');

      expect(result).toContainEqual({
        key: 'sessionToken',
        value: 'session-123',
      });
    });
  });

  describe('Edge cases', () => {
    it('should handle empty security parameters', () => {
      const securityParameters: SecurityParameterGroup = {};
      const envVariables: SimpleRecord = {};

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'header');

      expect(result).toEqual([]);
    });

    it('should handle deeply nested environment variables', () => {
      const securityParameters: SecurityParameterGroup = {
        Authorization: {
          type: 'http',
          scheme: 'bearer',
        },
      };

      const envVariables: SimpleRecord = {
        header: {
          Authorization: {
            HTTP: {
              bearer: 'nested-token',
              basic: 'should-not-use-this',
            },
          },
        },
      };

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'header');

      expect(result).toContainEqual({
        key: 'Authorization',
        value: 'nested-token',
      });
    });

    it('should handle environment variables with wrong location', () => {
      const securityParameters: SecurityParameterGroup = {
        apiKey: {
          type: 'apiKey',
        },
      };

      const envVariables: SimpleRecord = {
        header: {
          apiKey: {
            API_KEY: 'wrong-location',
          },
        },
      };

      // Looking in 'query' but env var is in 'header'
      const result = convertSecurityParameterSection(securityParameters, envVariables, 'query');

      expect(result).toEqual([
        {
          key: 'apiKey',
          value: undefined,
        },
      ]);
    });

    it('should handle special characters in parameter names', () => {
      const securityParameters: SecurityParameterGroup = {
        'x-special-key-123': {
          type: 'apiKey',
        },
      };

      const envVariables: SimpleRecord = {
        header: {
          'x-special-key-123': {
            API_KEY: 'special-value',
          },
        },
      };

      const result = convertSecurityParameterSection(securityParameters, envVariables, 'header');

      expect(result).toContainEqual({
        key: 'x-special-key-123',
        value: 'special-value',
      });
    });
  });
});
